import boto3
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    viewer_ip = request['clientIp']

    enrich_url_header = 'X-Enrich-URL'
    enrich_urls = request.get('headers', {}).get(enrich_url_header, [])

    if enrich_urls:
        client = boto3.client('logs')
        log_stream_name = f'/aws/lambda/{context.functionName}'
        log_group_name = '/aws/lambda/function'

        for url in enrich_urls:
            try:
                response = requests.get(url)
                enriched_data = response.json()
                # Process the enriched data and modify the request
                request['headers']['X-Enriched-Data'] = [{'key': 'enriched_data', 'value': enriched_data}]
                log_message = f'Enriched {url} for viewer IP {viewer_ip}'
                client.put_log_events(
                    logGroupName=log_group_name,
                    logStreamName=log_stream_name,
                    logEvents=[{'timestamp': int(round(time.time() * 1000)), 'message': log_message}]
                )
            except Exception as e:
                log_message = f'Failed to enrich {url} for viewer IP {viewer_ip}: {str(e)}'
                client.put_log_events(
                    logGroupName=log_group_name,
                    logStreamName=log_stream_name,
                    logEvents=[{'timestamp': int(round(time.time() * 1000)), 'message': log_message}]
                )

    return request